 17→USTRUCT(BlueprintType)
 18→struct FLFPHexCoordinates
 19→{
 20→	GENERATED_USTRUCT_BODY()
 21→
 22→public:
 23→	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "HexCoordinates")
 24→	int32 Q; // 立方坐标 q
 25→
 26→	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "HexCoordinates")
 27→	int32 R; // 立方坐标 r
 28→
 29→	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "HexCoordinates")
 30→	int32 S; // 立方坐标 s（自动计算）
 31→
 32→	FLFPHexCoordinates() : Q(0), R(0), S(0) {}
 33→
 34→	FLFPHexCoordinates(int32 q, int32 r) : Q(q), R(r), S(-q - r) {}
 35→
 36→	// 坐标转换函数
 37→	FVector ToWorldLocation(float Size, float VerticalScale = 1.0f) const
 38→	{
 39→		// 平顶六边形布局
 40→		const float HorizontalSpacing = Size * FMath::Sqrt(3.f); // 水平间距
 41→		const float VerticalSpacing = Size * 1.5f * VerticalScale; // 垂直间距（应用缩放）
 42→
 43→		float X = HorizontalSpacing * (Q + R * 0.5f);
 44→		float Y = VerticalSpacing * R;
 45→
 46→		return FVector(X, Y, 0);
 47→	}
 48→
 49→	// 计算距离
 50→	static int32 Distance(const FLFPHexCoordinates& A, const FLFPHexCoordinates& B)
 51→	{
 52→		return (FMath::Abs(A.Q - B.Q) +
 53→			FMath::Abs(A.R - B.R) +
 54→			FMath::Abs(A.S - B.S)) / 2;
 55→	}
 56→
 57→	// 获取所有相邻坐标
 58→	TArray<FLFPHexCoordinates> GetNeighbors() const
 59→	{
 60→		// 六边形的邻居方向
 61→		static const TArray<FLFPHexCoordinates> Directions = {
 62→			FLFPHexCoordinates(+1,  0), // 东
 63→			FLFPHexCoordinates(+1, -1), // 东北
 64→			FLFPHexCoordinates(0, -1), // 西北
 65→			FLFPHexCoordinates(-1,  0), // 西
 66→			FLFPHexCoordinates(-1, +1), // 西南
 67→			FLFPHexCoordinates(0, +1)  // 东南
 68→		};
 69→
 70→		TArray<FLFPHexCoordinates> Neighbors;
 71→		for (const auto& Dir : Directions)
 72→		{
 73→			Neighbors.Add(FLFPHexCoordinates(Q + Dir.Q, R + Dir.R));
 74→		}
 75→		return Neighbors;
 76→	}
 77→
 78→	static FLFPHexCoordinates FromWorldLocation(const FVector2D& WorldLocation, float HexSize, float VerticalScale)
 79→	{
 80→		// 平顶六边形坐标转换公式
 81→		const float Sqrt3 = FMath::Sqrt(3.f);
 82→
 83→		float unit_x = HexSize * Sqrt3;
 84→		float unit_y = HexSize * 1.5f;
 85→		float minDistanceLimit = HexSize * Sqrt3 * 0.5f;
 86→		float WorldLocation_X = WorldLocation.X;
 87→		float WorldLocation_Y = WorldLocation.Y / VerticalScale;
 88→
 89→		TArray<FVector2D> anchors;
 90→		anchors.Add(FVector2D::ZeroVector);
 91→		anchors.Add(FVector2D::ZeroVector);
 92→		anchors.Add(FVector2D::ZeroVector);
 93→		float distance;
 94→		float minDistance = 10000;
 95→		int index = 0;
 96→
 97→		int32 index_x = WorldLocation_X / unit_x - (WorldLocation_X < 0 ? 1 : 0);
 98→		int32 index_y = WorldLocation_Y / unit_y - (WorldLocation_Y < 0 ? 1 : 0);
 99→		anchors[0].X = index_x * unit_x;
100→		anchors[1].X = (index_x + 0.5) * unit_x;
101→		anchors[2].X = (index_x + 1) * unit_x;
102→		if (index_y % 2 == 0)
103→		{
104→			anchors[0].Y = anchors[2].Y = index_y * unit_y;
105→			anchors[1].Y = (index_y + 1) * unit_y;
106→		}
107→		else
108→		{
109→			anchors[0].Y = anchors[2].Y = (index_y + 1) * unit_y;
110→			anchors[1].Y = index_y * unit_y;
111→		}
112→		// 找出距离点最近的一个锚点
113→		for (int i = 0; i < 3; i++)
114→		{
115→			// 计算欧式距离
116→			//UE_LOG(LogTemp, Warning, TEXT("anchor:(%f,%f)"), anchors[i].X, anchors[i].Y);
117→			distance = FVector2D::Distance(FVector2D(WorldLocation_X, WorldLocation_Y), FVector2D(anchors[i].X, anchors[i].Y));
118→			//UE_LOG(LogTemp, Warning, TEXT("distance:(%f)"), distance);
119→			// 如果已经十分确定了
120→			if (distance < minDistanceLimit)
121→			{
122→				index = i;
123→				break;
124→			}
125→
126→			// 记录最小距离和索引
127→			if (distance < minDistance)
128→			{
129→				minDistance = distance;
130→				index = i;
131→			}
132→		}
133→
134→		int32 q = FMath::RoundToFloat((anchors[index].X / Sqrt3 - anchors[index].Y / 3.f) / HexSize);
135→		int32 r = FMath::RoundToFloat(anchors[index].Y * 2.f / 3.f / HexSize);
136→
137→		return FLFPHexCoordinates(q, r);
138→	}
139→};
