 52→void ALFPHexTile::SetMovementHighlight(bool bActive)
 53→{
 54→	if (bActive && MovementRangeSprite)
 55→	{
 56→		SpriteComponent->SetSprite(MovementRangeSprite);
 57→	}
 58→	else if (DefaultSprite)
 59→	{
 60→		SpriteComponent->SetSprite(DefaultSprite);
 61→	}
 62→	else if (!DefaultSprite)
 63→	{
 64→		SpriteComponent->SetSprite(nullptr);
 65→	}
