102→void ALFPHexTile::SetTerrainData(ULFPTerrainDataAsset* InTerrainData)
103→{
104→	TerrainData = InTerrainData;
105→	if (TerrainData)
106→	{
107→		// 从地形数据同步属性
108→		bIsWalkable = TerrainData->bIsWalkable;
109→
110→		// 设置基础精灵
111→		if (TerrainData->DefaultSprite)
112→		{
113→			DefaultSprite = TerrainData->DefaultSprite;
114→			SpriteComponent->SetSprite(DefaultSprite);
115→		}
116→	}
117→}
