129→void ALFPHexTile::SetRangeSprite(EUnitRange UnitRange)
130→{
131→	switch (UnitRange)
132→	{
133→	case EUnitRange::UR_Default:
134→		SpriteComponent->SetSprite(DefaultSprite);
135→		break;
136→	case EUnitRange::UR_Move:
137→		SpriteComponent->SetSprite(MovementRangeSprite);
138→		break;
139→	case EUnitRange::UR_Attack:
140→		SpriteComponent->SetSprite(AttackRangeSprite);
141→		break;
142→	case EUnitRange::UR_SkillEffect:
143→		SpriteComponent->SetSprite(SkillEffectRangeSprite);
144→	default:
145→		break;
146→	}
147→}
